effect([step, min, max, value], function fixValue([$step, $min, $max, $value]) {
	const isValidValue = (v: number) => {
		const snappedValue = snapValueToStep(v, $min, $max, $step);
		return snappedValue === v;
	};

	const gcv = (v: number) => {
		return snapValueToStep(v, $min, $max, $step);
	};

	if ($value.some((v) => !isValidValue(v))) {
		value.update((prev) => {
			return prev.map(gcv);
		});
	}
});

export function pointInPolygon(point: Point, polygon: Polygon) {
	let inside = false;
	for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
		const xi = polygon[i].x;
		const yi = polygon[i].y;
		const xj = polygon[j].x;
		const yj = polygon[j].y;

		const intersect =
			yi > point.y !== yj > point.y && point.x < ((xj - xi) * (point.y - yi)) / (yj - yi) + xi;
		if (intersect) inside = !inside;
	}
	return inside;
}

export function getPointsFromEl(el: HTMLElement): Array<Point> {
	const rect = el.getBoundingClientRect();
	return [
		{ x: rect.left, y: rect.top },
		{ x: rect.right, y: rect.top },
		{ x: rect.right, y: rect.bottom },
		{ x: rect.left, y: rect.bottom },
	];
}

export function makeHullFromElements(els: Array<HTMLElement>): Array<Point> {
	const points = els.flatMap((el) => getPointsFromEl(el));
	return makeHull(points);
}

export function modifyLines(
    text: string,
    replacementFn: (line: string, lineIdx: number) => string
): string {
    let idx = 0;
    return text
        .split('\r\n')
        .map((l1) =>
            l1
                .split('\n')
                .map((line) => replacementFn(line, idx++))
                .join('\n')
        )
        .join('\r\n');
}

const update = ({ value, selected: isSelected }) => {
  if (isSelected) {
    if (!$selectedValues.includes(value)) {
      selectedValues.update((values) => [...values, value]);
      dispatch("select", value);
    }
  } else {
    if ($selectedValues.includes(value)) {
      selectedValues.update((values) => values.filter((v) => v !== value));
      dispatch("deselect", value);
    }
  }
};

if ((e.clientX !== 0 || e.clientY !== 0) && container) {
  const parentRect = container.getBoundingClientRect();
  if (
    e.clientX >= parentRect.left &&
    e.clientX <= parentRect.right &&
    e.clientY >= parentRect.top &&
    e.clientY <= parentRect.bottom
  ) {
    x = e.clientX - offsetX - parentRect.left;
    y = e.clientY - offsetY - parentRect.top;
  }
}

if ((e.clientX !== 0 || e.clientY !== 0) && containerTop) {
